import { writeOutput } from "./codegen";

const DOCS_URL = "https://www.revenuecat.com/docs/projects/authentication";
const PLACEHOLDER_VALUE =
  "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalCoffeeSaf";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from RevenueCat API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:revenuecat",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const revenuecatFirewall = {",
    '  name: "revenuecat",',
    '  description: "RevenueCat API",',
    "  placeholders: {",
    `    REVENUECAT_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.revenuecat.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.REVENUECAT_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating RevenueCat firewall config...");
  const ts = generateTypeScript();
  writeOutput("revenuecat", ts, import.meta.dirname);
}
